sql:
SELECT firstname, lastname, income
FROM family_members
WHERE income = (SELECT MAX(income) FROM family_members);

SELECT family_id, firstname, lastname, birthdate
FROM family_members
WHERE strftime('%Y', 'now') - strftime('%Y', birthdate) - (strftime('%m-%d', 'now') < strftime('%m-%d', birthdate)) > 50;

SELECT family_id, firstname, lastname
FROM family_members
WHERE (julianday('now') - julianday(birthdate)) / 365 < 18;

SELECT language, religion, COUNT(*) AS num_of_families
FROM families
GROUP BY language, religion;

SELECT DISTINCT family_id
FROM households
WHERE housing_status = 'owned';

